```javascript
const { Client, GatewayIntentBits } = require('discord.js');

const client = new Client({ 
    intents: [GatewayIntentBits.Guilds, GatewayIntentBits.GuildMembers]
});

client.on('ready', () => {
    console.log(`Logged in as ${client.user.tag}`);
});

client.on('interactionCreate', async (interaction) => {
    if (!interaction.isCommand()) return;

    const { commandName, options } = interaction;

    if (commandName === 'ban') {
        const userOption = options.get('user');
        const reasonOption = options.get('reason');

        if (!userOption || !userOption.user) {
            return interaction.reply({ content: 'Please provide a user to ban.', ephemeral: true });
        }

        const targetUser = userOption.user;
        const reason = reasonOption?.value || 'No reason specified.';

        if (!interaction.member.permissions.has('BAN_MEMBERS')) {
            return interaction.reply({ content: 'You do not have permission to use this command.', ephemeral: true });
        }

        try {
            await interaction.guild.members.ban(targetUser, { reason });
            interaction.reply(`Successfully banned ${targetUser.tag}. Reason: ${reason}`);
        } catch (error) {
            console.error(`Failed to ban user: ${error}`);
            interaction.reply({ content: 'Failed to ban the specified user.', ephemeral: true });
        }
    }
});

client.login('YOUR_BOT_TOKEN');
```

