Here's an example implementation of a C++ function that converts Markdown formatted text to HTML formatted text:

```cpp
#include <iostream>
#include <string>
#include <regex>

std::string markdownToHtml(const std::string& markdown) {
    std::string html = markdown;

    // Convert headers
    std::regex headerRegex("# (.+)");
    html = std::regex_replace(html, headerRegex, "<h1>$1</h1>");

    // Convert bold text
    std::regex boldRegex("\\*\\*(.+?)\\*\\*");
    html = std::regex_replace(html, boldRegex, "<strong>$1</strong>");

    // Convert italic text
    std::regex italicRegex("\\*(.+?)\\*");
    html = std::regex_replace(html, italicRegex, "<em>$1</em>");

    // Convert links
    std::regex linkRegex("\\[(.+)\\]\\((.+)\\)");
    html = std::regex_replace(html, linkRegex, "<a href=\"$2\">$1</a>");

    // Convert code blocks
    std::regex codeBlockRegex("```(.+?)```");
    html = std::regex_replace(html, codeBlockRegex, "<pre><code>$1</code></pre>");

    return html;
}

int main() {
    std::string markdown = "# Heading\nThis is **bold** and *italic* text.\n[Link](https://example.com)\n```cpp\nint main() {\n    std::cout << \"Hello, world!\";\n    return 0;\n}\n```";
    std::string html = markdownToHtml(markdown);
    std::cout << html << std::endl;

    return 0;
}
```

This function performs basic conversions for headers, bold and italic text, links, and code blocks. You can extend it to handle more Markdown syntax as needed.

